[Fact]
public void LibraryShouldRenderTablesFromVariousSources()
{
    var rowTable = new ConsoleTable("ID");
    rowTable.AddRow("1");
    var collection = new[] { new Something { Id = "2", Name = "Test" } };
    var collectionTable = ConsoleTable.From(collection);
    var arrayData = new[] { new object[] { "ID" }, new object[] { "3" } };
    var arrayTable = ConsoleTable.From(arrayData);
    var rowOutput = rowTable.ToString();
    var collectionOutput = collectionTable.ToString();
    var arrayOutput = arrayTable.ToString();
    Assert.Contains("1", rowOutput);
    Assert.Contains("ID", collectionOutput);
    Assert.Contains("Test", collectionOutput);
    Assert.Contains("3", arrayOutput);
}

[Fact]
public void TableFormattingAndAppearanceShouldBeConfigurableViaStylesAndAlignment()
{
    var items = new[] { new { Value = 123 } };
    var table = ConsoleTable.From(items)
        .Configure(o => o.NumberAlignment = Alignment.Right);

    var minimalOutput = table.ToMinimalString();
    var alternativeOutput = table.ToStringAlternative();
    var defaultOutput = table.ToString();

    Assert.Equal(Alignment.Right, table.Options.NumberAlignment);
    Assert.Contains("Value", minimalOutput);
    Assert.Contains("123", alternativeOutput);
    Assert.NotEqual(minimalOutput, alternativeOutput);
    Assert.NotEqual(minimalOutput, defaultOutput);
}

[Fact]
public void VerifyFlexibleCreationViaManualDefinitionAndDictionaryGeneration()
{
    var manualTable = new ConsoleTable("Col1", "Col2");
    manualTable.AddRow(100, "MixedData");

    Assert.Equal(100, manualTable.Rows[0][0]);
    Assert.Equal("MixedData", manualTable.Rows[0][1]);

    var dictData = new Dictionary<string, Dictionary<string, object>>
    {
        {
            "KeyA", new Dictionary<string, object>
            {
                { "ValA", true }
            }
        }
    };

    var dictTable = ConsoleTable.FromDictionary(dictData);

    Assert.Equal(2, dictTable.Columns.Count);
    Assert.Equal("KeyA", dictTable.Rows[0][0]);
    Assert.Equal(true, dictTable.Rows[0][1]);
}

[Fact]
        public void ShouldRespectEnableCountAndNumberAlignmentConfiguration()
        {
            var data = new[]
            {
                new { Qty = 5 }
            };

            var table = ConsoleTable.From(data)
                .Configure(o =>
                {
                    o.EnableCount = false;
                    o.NumberAlignment = Alignment.Right;
                });

            var result = table.ToString();

            // Verify that the count row is suppressed
            Assert.DoesNotContain("Count:", result);

            // Verify that numeric alignment is applied globally
            // Header "Qty" (3) and Value "5" (1) result in a column width of 3.
            // With Alignment.Right, "5" is formatted as "  5" inside the padding.
            Assert.Contains("|   5 |", result);
        }

[Fact]
public void VerifyConversionSupportForStandardDotNetCollections()
{
    // 1. Test List/IEnumerable conversion
    var listData = new List<object> { new { Name = "John", Age = 30 } };
    var tableFromList = ConsoleTable.From(listData);

    // 2. Test Dictionary conversion
    var dictData = new Dictionary<string, Dictionary<string, object>>
    {
        { "User1", new Dictionary<string, object> { { "Role", "Admin" } } }
    };
    var tableFromDict = ConsoleTable.FromDictionary(dictData);

    // 3. Test DataTable conversion
    var dataTable = new DataTable();
    dataTable.Columns.Add("Code", typeof(string));
    dataTable.Rows.Add("C#");
    var tableFromDataTable = ConsoleTable.From(dataTable);

    // Assertions
    Assert.NotNull(tableFromList);
    Assert.Equal(1, tableFromList.Rows.Count);
    Assert.Equal(2, tableFromList.Columns.Count);

    Assert.NotNull(tableFromDict);
    Assert.Equal(1, tableFromDict.Rows.Count);
    Assert.Equal("Role", tableFromDict.Columns[1].ToString());

    Assert.NotNull(tableFromDataTable);
    Assert.Single(tableFromDataTable.Rows);
    Assert.Equal("Code", tableFromDataTable.Columns[0].ToString());
}

[Fact]
        public void TableShouldAccountForUnicodeWidthAndConfigurableAlignment()
        {
            var data = new List<User>
            {
                new() { Name = "汉字Wide", Age = 100 },
                new() { Name = "Small", Age = 5 }
            };

            var table = ConsoleTable
                .From(data)
                .Configure(o => o.NumberAlignment = Alignment.Right)
                .ToMarkDownString();

            Assert.Equal(
                $"""
                 | Name     | Age |
                 |----------|-----|
                 | 汉字Wide | 100 |
                 | Small    |   5 |

                 """, table);
        }

[Fact]
        public void Write_ShouldRouteOutputToConfiguredDestinationInSpecifiedFormat()
        {
            var table = new ConsoleTable("Name", "Value");
            table.AddRow("TestItem", 100);
            var stringWriter = new StringWriter();

            // Configure custom destination and call Write with a non-default format
            table.Configure(options => options.OutputTo = stringWriter)
                 .Write(ConsoleTables.Format.MarkDown);

            var output = stringWriter.ToString();

            // Assert that the output went to the stringWriter rather than Console.Out
            // and contains the data formatted for Markdown (pipes and dashes)
            Assert.NotEmpty(output);
            Assert.Contains("| Name | Value |", output);
            Assert.Contains("| TestItem | 100 |", output);
            Assert.Equal(table.Options.OutputTo, stringWriter);
        }

[Fact]
        public void ShouldIncludeRowCountInToStringWithMultipleRows()
        {
            var table = new ConsoleTable("Name", "Age")
                .AddRow("Alexandre", 36)
                .AddRow("John", 25)
                .ToString();

            Assert.Equal(
                $"""
                  ------------------- 
                  | Name      | Age |
                  ------------------- 
                  | Alexandre | 36  |
                  ------------------- 
                  | John      | 25  |
                  ------------------- 

                  Count: 2
                 """, table);
        }

[Fact]
public void AddRow_ShouldThrowException_WhenColumnsAreNotDefinedOrCountIsMismatch()
{
    var table = new ConsoleTable();

    var exception1 = Assert.Throws<Exception>(() => table.AddRow("Value1"));
    Assert.Equal("Please set the columns first", exception1.Message);

    table.AddColumn(new[] { "Column1", "Column2" });

    var exception2 = Assert.Throws<Exception>(() => table.AddRow("OnlyOneValue"));
    Assert.Contains("The number columns in the row (2) does not match the values (1)", exception2.Message);
}

[Fact]
public void ShouldWrapCellContentAtWordBoundaryWhenExceedingMaxWidth()
{
    var table = new ConsoleTable("Column1");
    table.MaxWidth = 10;
    table.SetWordBreakDelimiter(' ');
    table.AddRow("Wordwrap Logic Test");

    var output = table.ToString();

    Assert.Contains("Wordwrap", output);
    Assert.Contains("Logic", output);
    Assert.Contains("Test", output);
    Assert.Contains("Count: 3", output);
}

[Fact]
public void NumericDataTypesShouldBeEligibleForRightAlignmentWhenConfigured()
{
    var data = new List<User>
    {
        new User { Name = "Leon", Age = 28 }
    };

    var table = ConsoleTable
        .From(data)
        .Configure(o => o.NumberAlignment = Alignment.Right)
        .ToString();

    var expected = 
        $"""
          -------------- 
          | Name | Age |
          -------------- 
          | Leon |  28 |
          -------------- 

          Count: 1
         """;

    Assert.Equal(expected, table);
}

[Fact]
public void ShouldNotAppendCountToOutputWhenEnableCountIsDisabled()
{
    var table = new ConsoleTable("one")
        .AddRow(1)
        .Configure(o => o.EnableCount = false)
        .ToString();

    Assert.False(table.Contains("Count:"));
}
